    SELECT a, b FROM t1 GROUP BY a;

SELECT sorgusunu çalıştırırsanız, Microsoft SQL Server `b` sütununun GROUP BY içinde yer almasını veya bir agregat fonksiyon içinde kullanılmasını beklediği için bir hata alırsınız. Aşağıdaki iki örnek bu hatayı düzeltecektir.

